@Repository
public interface NetworkProviderRepository extends JpaRepository<NetworkProvider, Long> {
    @Query("SELECT p FROM NetworkProvider p " +
           "JOIN FETCH p.network n " +
           "WHERE p.npiNumber = :npiNumber " +
           "AND p.effectiveDate <= :asOfDate " +
           "AND (p.terminationDate IS NULL OR p.terminationDate > :asOfDate)")
    Optional<NetworkProvider> findActiveByNpi(
        @Param("npiNumber") String npiNumber,
        @Param("asOfDate") LocalDate asOfDate
    );
}

@Query(value = "SELECT c.claim_id, c.member_id, c.total_billed, c.paid_amount, " +
       "c.claim_status, c.service_from_date " +
       "FROM claim c " +
       "WHERE c.rendering_provider_id = :providerId " +
       "AND c.service_from_date BETWEEN :startDate AND :endDate " +
       "AND c.claim_status NOT IN ('VOID','DUPLICATE') " +
       "ORDER BY c.service_from_date DESC", nativeQuery = true)
List<ClaimSummary> findClaimsByProviderAndDateRange(
    @Param("providerId") Long providerId,
    @Param("startDate") LocalDate startDate,
    @Param("endDate") LocalDate endDate
);

