    "FROM prior_auth a " +
    "WHERE a.member_id = ? " +
    "AND a.procedure_code = ? " +
    "AND a.auth_status = 'APPROVED' " +
    "AND a.expiration_date >= CURRENT_DATE";
PreparedStatement ps = conn.prepareStatement(sql);
ps.setLong(1, memberId);
